#include <bits/stdc++.h>
using namespace std;
int n,m,v[26],p[26],dp[26][30004];
int main(){
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&v[i],&p[i]);
    for(int i=1;i<=n;i++)
        for(int j=0;j<=m;j++)
            if(j>=v[i])
                dp[i][j]=max(dp[i-1][j],dp[i-1][j-v[i]]+v[i]*p[i]);
            else
                dp[i][j]=dp[i-1][j];
    printf("%d",dp[n][m]);
    return 0;
}
